proof fn phi_2_subtract_self_aligned(a: nat, c: nat)
    requires
        aligned(a, c),
        c > 0,
    ensures
        aligned(0nat, c),
{
    subtract_mod_eq_zero(a, a, c);
}

proof fn phi_3_subtract_zero_aligned(b: nat, c: nat)
    requires
        aligned(b, c),
        c > 0,
    ensures
        aligned(b, c),
{
    subtract_mod_eq_zero(0, b, c);
}

proof fn phi_4_subtract_consecutive_multiples(c: nat, k1: nat, k2: nat)
    requires
        c > 0,
        k1 <= k2,
    ensures
        aligned((k2 * c - k1 * c) as nat, c),
{
    assert(aligned(k1 * c, c)) by {
        assert((k1 * c) % c == 0) by (nonlinear_arith) requires c > 0;
    };
    assert(aligned(k2 * c, c)) by {
        assert((k2 * c) % c == 0) by (nonlinear_arith) requires c > 0;
    };
    assert(k1 * c <= k2 * c) by (nonlinear_arith) requires k1 <= k2, c > 0;
    subtract_mod_eq_zero(k1 * c, k2 * c, c);
}

proof fn phi_5_vstd_lemma_sub_mod_noop_trusted(a: int, b: int, c: int)
    requires
        c > 0,
    ensures
        (b - a) % c == ((b % c) - (a % c)) % c,
{
    vstd::arithmetic::div_mod::lemma_sub_mod_noop(b, a, c);
}
